"""
Pytest tests for Patient Consent Management Requirements:
- Patient shall grant or revoke consent for data sharing
- Revoked consent shall be enforced within 15 minutes
- AuditEvent must be emitted for every operation (end-to-end)
"""

import time
import uuid
from datetime import datetime, timezone, timedelta
from unittest.mock import MagicMock, patch, call
from dataclasses import dataclass, field
from typing import Optional
import pytest


# ---------------------------------------------------------------------------
# Domain models (stand-ins for real FHIR/service objects)
# ---------------------------------------------------------------------------

@dataclass
class Consent:
    consent_id: str
    patient_id: str
    status: str          # "active" | "inactive" | "proposed"
    scope: str           # e.g. "patient-privacy"
    granted_at: Optional[datetime] = None
    revoked_at: Optional[datetime] = None
    actor_id: Optional[str] = None   # who performed the action

    def is_active(self) -> bool:
        return self.status == "active"


@dataclass
class AuditEvent:
    event_id: str
    action: str          # "grant" | "revoke" | "access" | "enforce"
    patient_id: str
    actor_id: str
    resource_type: str
    resource_id: str
    outcome: str         # "success" | "failure"
    recorded_at: datetime
    details: dict = field(default_factory=dict)


@dataclass
class DataAccessRequest:
    requester_id: str
    patient_id: str
    resource_type: str
    purpose: str


# ---------------------------------------------------------------------------
# Fake in-memory consent store (simulates a repository)
# ---------------------------------------------------------------------------

class FakeConsentRepository:
    def __init__(self):
        self._consents: dict[str, Consent] = {}

    def save(self, consent: Consent) -> Consent:
        self._consents[consent.consent_id] = consent
        return consent

    def find_by_patient(self, patient_id: str) -> Optional[Consent]:
        for c in self._consents.values():
            if c.patient_id == patient_id:
                return c
        return None

    def find_by_id(self, consent_id: str) -> Optional[Consent]:
        return self._consents.get(consent_id)

    def all(self) -> list[Consent]:
        return list(self._consents.values())


# ---------------------------------------------------------------------------
# Fake in-memory audit log
# ---------------------------------------------------------------------------

class FakeAuditRepository:
    def __init__(self):
        self._events: list[AuditEvent] = []

    def save(self, event: AuditEvent) -> AuditEvent:
        self._events.append(event)
        return event

    def find_by_patient(self, patient_id: str) -> list[AuditEvent]:
        return [e for e in self._events if e.patient_id == patient_id]

    def find_by_action(self, action: str) -> list[AuditEvent]:
        return [e for e in self._events if e.action == action]

    def find_by_resource(self, resource_id: str) -> list[AuditEvent]:
        return [e for e in self._events if e.resource_id == resource_id]

    def all(self) -> list[AuditEvent]:
        return list(self._events)


# ---------------------------------------------------------------------------
# Consent Service (system-under-test)
# ---------------------------------------------------------------------------

class ConsentEnforcementError(Exception):
    pass


class ConsentNotFoundError(Exception):
    pass


class ConsentService:
    """
    Manages patient consent lifecycle and enforces access based on consent
    status.  Every mutating operation emits an AuditEvent.
    """

    REVOCATION_ENFORCEMENT_WINDOW_SECONDS = 15 * 60  # 15 minutes

    def __init__(
        self,
        consent_repo: FakeConsentRepository,
        audit_repo: FakeAuditRepository,
        clock=None,   # injectable for time-travel in tests
    ):
        self._consent_repo = consent_repo
